                <button 
                    onClick={(e) => handleSpeak(e, backDisplayText, '-back')}
                    className="absolute bottom-6 right-6 md:bottom-8 md:right-8 w-10 h-10 md:w-12 md:h-12 flex items-center justify-center bg-white text-slate-900 rounded-full hover:bg-emerald-400 hover:text-white shadow-xl shadow-black/20 transition-all z-20 hover:scale-110 active:scale-95"
                    title="Read Aloud"
                >
                    {isSpeaking && speakingId?.endsWith('-back') ? (
                        <div className="flex gap-0.5 items-center justify-center h-3">
                            <div className="w-0.5 h-full bg-current rounded-full animate-[pulse_0.6s_ease-in-out_infinite]"></div>
                            <div className="w-0.5 h-3/4 bg-current rounded-full animate-[pulse_0.6s_ease-in-out_0.2s_infinite]"></div>
                            <div className="w-0.5 h-1/2 bg-current rounded-full animate-[pulse_0.6s_ease-in-out_0.4s_infinite]"></div>
                        </div>
                    ) : (
                        <Volume2 size={18} md:size={20} />
                    )}
                </button>
            </div>

          </div>
        </div>
      </div>

      {/* Navigation - Bottom */}
      <div className="px-6 pb-6 pt-4 flex justify-center gap-4 md:gap-6 items-center shrink-0">
        <button 
          onClick={handlePrev} 
          disabled={currentIndex === 0}
          className="w-12 h-12 md:w-14 md:h-14 rounded-2xl bg-white border border-slate-200 flex items-center justify-center text-slate-400 disabled:opacity-40 disabled:cursor-not-allowed hover:border-slate-300 hover:text-slate-600 hover:bg-slate-50 transition-all shadow-sm active:translate-y-0.5"
        >
          <ArrowLeft size={20} md:size={24} />
        </button>

        {/* Main Action Button - RED */}
        <button 
            onClick={() => setIsFlipped(!isFlipped)}
            className="h-12 md:h-14 px-8 md:px-12 rounded-2xl bg-rose-600 flex items-center gap-3 text-white hover:bg-rose-500 transition-all shadow-lg shadow-rose-200 hover:shadow-xl active:translate-y-0.5 font-black uppercase text-[10px] md:text-xs tracking-[0.2em] group"
        >
            <RotateCcw size={16} md:size={18} className={`transition-transform duration-500 ${isFlipped ? '-rotate-180' : 'rotate-0'} group-hover:-rotate-180`} />
            Flip Card
        </button>

        <button 
          onClick={handleNext} 
          disabled={currentIndex === activeData.length - 1}
          className="w-12 h-12 md:w-14 md:h-14 rounded-2xl bg-white border border-slate-200 flex items-center justify-center text-slate-400 disabled:opacity-40 disabled:cursor-not-allowed hover:border-slate-300 hover:text-slate-600 hover:bg-slate-50 transition-all shadow-sm active:translate-y-0.5"
        >
          <ArrowRight size={20} md:size={24} />
        </button>
      </div>

      <FilterModal
        isOpen={isFilterOpen}
        onClose={() => setIsFilterOpen(false)}
        categories={categories}
        selectedCategories={selectedCategories}
        onToggleCategory={(cat) => setSelectedCategories(prev => prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat])}
        onClearAll={() => { setSelectedCategories([]); setShowImagesOnly(false); setShowMistakesOnly(false); }}
        onWipeVault={mistakesVault.length > 0 ? handleWipeVault : undefined}
        mainOptions={filterOptions}
        title="Deck Filters"
      />
    </div>
  );
};

