              </span>
              <span className="text-base md:text-lg font-black text-slate-900 font-display flex items-baseline gap-1">
                 {currentIndex + 1} 
                 <span className="text-xs md:text-sm font-bold text-slate-300">/ {activeData.length}</span>
              </span>
           </div>
        </div>

        <div className="flex items-center gap-2">
           <button 
             onClick={() => { setIsReversed(!isReversed); setIsFlipped(false); }}
